import React, { Component } from "react";
import "./index.css";
import profileImg from "./image/1.jpg";

class App extends Component {
    state = {
        firstName: "",
        lastName: "",
        mobile: "",
        password: "",
        email: "",
        registeredDate: "",
        address1: "",
        address2: "",
        province: "",
        district: "",
        showPassword: false,
    };

    handleChange = (e) => {
        this.setState({ [e.target.name]: e.target.value });
    };

    togglePassword = () => {
        this.setState({ showPassword: !this.state.showPassword });
    };

    handleSubmit = (e) => {
        e.preventDefault();
        alert("Profile updated!");
    };

    render() {
        return (
            <div className="profile-container"
                style={{
                    display: "flex",
                    justifyContent: "center",
                    alignItems: "flex-start",
                    minHeight: "100vh",
                    background: "#f7f7f7"
                }}>
                {/* Left: Profile Image & Info */}
                <div
                    style={{
                        width: 320,
                        background: "#fff",
                        borderRadius: 12,
                        boxShadow: "0 2px 8px #eee",
                        padding: 32,
                        marginRight: 32,
                        textAlign: "center"
                    }}>
                    <img
                        src={profileImg}
                        alt="Profile"
                        style={{
                            width: 120,
                            height: 120,
                            borderRadius: "30%",
                            objectFit: "cover",
                            marginBottom: 16
                        }}
                    />
                    <h4 style={{ margin: "8px 0 4px" }}>
                        {this.state.firstName} {this.state.lastName}
                    </h4>
                    <div style={{ color: "#888", fontSize: 15, marginBottom: 24 }}>
                        {this.state.email}
                    </div>
                    <button className="btn btn-primary">Update Profile Image</button>
                </div>
                {/* Right: Profile Settings Form */}
                <div
                    style={{
                        flex: 1,
                        background: "#fff",
                        borderRadius: 12,
                        boxShadow: "0 2px 8px #eee",
                        padding: 32,
                        maxWidth: 600
                }}>

                    <h3 style={{ marginBottom: 24 }}>Profile Settings</h3>

                    <form onSubmit={this.handleSubmit}>
                        <div className="row mb-3">
                            <div className="col">
                                <label>First Name</label>
                                <input
                                    type="text"
                                    className="form-control"
                                    name="firstName"
                                    value={this.state.firstName}
                                    onChange={this.handleChange}
                                />
                            </div>

                            <div className="col">
                                <label>Last Name</label>
                                <input
                                    type="text"
                                    className="form-control"
                                    name="lastName"
                                    value={this.state.lastName}
                                    onChange={this.handleChange}
                                />
                            </div>
                        </div>

                        <div className="mb-3">
                            <label>Mobile</label>
                            <input
                                type="text"
                                className="form-control"
                                name="mobile"
                                value={this.state.mobile}
                                onChange={this.handleChange}
                            />
                        </div>

                        <div className="mb-3" style={{ position: "relative" }}>
                            <label>Password</label>

                            <input
                                type={this.state.showPassword ? "text" : "password"}
                                className="form-control"
                                name="password"
                                value={this.state.password}
                                onChange={this.handleChange}
                            />

                            <button
                                type="button"
                                className="btn btn-outline-secondary"
                                style={{
                                    position: "absolute",
                                    right: 8,
                                    top: 32,
                                    padding: "2px 8px"
                                }}
                                onClick={this.togglePassword}
                            >
                                <i className={`bi ${this.state.showPassword ? "bi-eye-slash" : "bi-eye"}`}></i>
                            </button>
                        </div>

                        <div className="mb-3">
                            <label>Email</label>
                            <input
                                type="email"
                                className="form-control"
                                name="email"
                                value={this.state.email}
                                onChange={this.handleChange}
                            />
                        </div>

                        <div className="mb-3">
                            <label>Registered Date</label>
                            <input
                                type="text"
                                className="form-control"
                                name="registeredDate"
                                value={this.state.registeredDate}
                                readOnly
                            />
                        </div>

                        <div className="mb-3">
                            <label>Address Line 1</label>
                            <input
                                type="text"
                                className="form-control"
                                name="address1"
                                value={this.state.address1}
                                onChange={this.handleChange}
                            />
                        </div>

                        <div className="mb-3">
                            <label>Address Line 2</label>
                            <input
                                type="text"
                                className="form-control"
                                name="address2"
                                value={this.state.address2}
                                onChange={this.handleChange}
                            />
                        </div>

                        <div className="row mb-3">
                            <div className="col">
                                <label>Province</label>
                                <input
                                    type="text"
                                    className="form-control"
                                    name="province"
                                    value={this.state.province}
                                    onChange={this.handleChange}
                                />
                            </div>

                            <div className="col">
                                <label>District</label>
                                <input
                                    type="text"
                                    className="form-control"
                                    name="district"
                                    value={this.state.district}
                                    onChange={this.handleChange}
                                />
                            </div>
                        </div>

                        <button type="submit" className="btn btn-success mt-2">
                            Update Profile
                        </button>
                    </form>
                </div>
            </div>
        );
    }
}

export default App;
